default: 0\n\t\t\t},\n\t\t\t// 是否禁用\n\t\t\tdisabled: {\n\t\t\t\ttype: Boolean,\n\t\t\t\tdefault: false\n\t\t\t},\n\t\t\tbackground: {\n\t\t\t\ttype: String,\n\t\t\t\tdefault: '#fff'\n\t\t\t},\n\t\t\t//是否显示动画,如果动画卡顿严重建议不开启\n\t\t\tanimation: {\n\t\t\t\ttype: Boolean,\n\t\t\t\tdefault: true\n\t\t\t},\n\t\t\t// 是否展开\n\t\t\topen: {\n\t\t\t\ttype: Boolean,\n\t\t\t\tdefault: false\n\t\t\t},\n\t\t\tisBorder: {\n\t\t\t\ttype: Boolean,\n\t\t\t\tdefault: true\n\t\t\t},\n\t\t\t// #ifdef APP-NVUE\n\t\t\tborderColor: {\n\t\t\t\ttype: String,\n\t\t\t\tdefault: '#EEEEEE'\n\t\t\t},\n\t\t\t// #endif\n\t\t\t// #ifndef APP-NVUE\n\t\t\tborderColor: {\n\t\t\t\ttype: String,\n\t\t\t\tdefault: ''\n\t\t\t},\n\t\t\t// #endif\n\t\t\tborderLeft: {\n\t\t\t\ttype: [Number, String],\n\t\t\t\tdefault: 0\n\t\t\t},\n\t\t\tarrow: {\n\t\t\t\ttype: Boolean,\n\t\t\t\tdefault: true\n\t\t\t},\n\t\t\tarrowColor: {\n\t\t\t\ttype: String,\n\t\t\t\tdefault: '#B2B2B2'\n\t\t\t},\n\t\t\tarrowRight: {\n\t\t\t\ttype: [Number, String],\n\t\t\t\tdefault: 24\n\t\t\t},\n\t\t\tcontentBg: {\n\t\t\t\ttype: String,\n\t\t\t\tdefault: '#fff'\n\t\t\t},\n\t\t\tmarginTop: {\n\t\t\t\ttype: [Number, String],\n\t\t\t\tdefault: 0\n\t\t\t},\n\t\t\tmarginBottom: {\n\t\t\t\ttype: [Number, String],\n\t\t\t\tdefault: 0\n\t\t\t}\n\n\t\t},\n\t\tdata() {\n\t\t\tconst elId = `fui_${Math.ceil(Math.random() * 10e5).toString(36)}`\n\t\t\treturn {\n\t\t\t\tisOpen: false,\n\t\t\t\tisHeight: null,\n\t\t\t\theight: 0,\n\t\t\t\telId\n\t\t\t}\n\t\t},\n\t\twatch: {\n\t\t\topen(val) {\n\t\t\t\tthis.isOpen = val\n\t\t\t}\n\t\t},\n\t\tupdated(e) {\n\t\t\tthis.$nextTick(() => {\n\t\t\t\tsetTimeout(() => {\n\t\t\t\t\tthis.init()\n\t\t\t\t}, 50)\n\t\t\t})\n\t\t},\n\t\tcreated() {\n\t\t\tthis.collapse = this.getCollapse()\n\t\t\tif (this.collapse && this.collapse.children.indexOf(this) === -1) {\n\t\t\t\tthis.collapse.children.push(this)\n\t\t\t}\n\t\t\tthis.oldHeight = 0\n\t\t},\n\t\t// #ifndef VUE3\n\t\t// TODO vue2\n\t\tbeforeDestroy() {\n\t\t\tthis.uninstall()\n\t\t},\n\t\t// #endif\n\t\t// #ifdef VUE3\n\t\t// TODO vue3\n\t\tbeforeUnmount() {\n\t\t\tthis.uninstall()\n\t\t},\n\t\t// #endif\n\t\tmounted() {\n\t\t\tthis.$nextTick(() => {\n\t\t\t\tsetTimeout(() => {\n\t\t\t\t\tthis.init()\n\t\t\t\t\tthis.isOpen = this.open;\n\t\t\t\t}, 50)\n\t\t\t})\n\t\t},\n\t\tmethods: {\n\t\t\tinit() {\n\t\t\t\t// #ifndef APP-NVUE\n\t\t\t\tthis.getCollapseHeight()\n\t\t\t\t// #endif\n\t\t\t\t// #ifdef APP-NVUE\n\t\t\t\tthis.getNvueHeight()\n\t\t\t\t// #endif\n\t\t\t},\n\t\t\tuninstall() {\n\t\t\t\tif (this.collapse) {\n\t\t\t\t\tthis.collapse.children.forEach((item, index) => {\n\t\t\t\t\t\tif (item === this) {\n\t\t\t\t\t\t\tthis.collapse.children.splice(index, 1)\n\t\t\t\t\t\t}\n\t\t\t\t\t})\n\t\t\t\t}\n\t\t\t},\n\t\t\tonClick(isOpen) {\n\t\t\t\tif (this.disabled) return\n\t\t\t\tthis.isOpen = isOpen\n\t\t\t\tif (this.collapse) {\n\t\t\t\t\tthis.collapse.collapseChange(this, isOpen, this.index)\n\t\t\t\t} else {\n\t\t\t\t\tthis.$emit('change', {\n\t\t\t\t\t\tindex: this.index,\n\t\t\t\t\t\tisOpen: isOpen\n\t\t\t\t\t})\n\t\t\t\t}\n\t\t\t},\n\t\t\tgetCollapseHeight(index = 0) {\n\t\t\t\tuni.createSelectorQuery()\n\t\t\t\t\t// #ifndef MP-ALIPAY\n\t\t\t\t\t.in(this)\n\t\t\t\t\t// #endif\n\t\t\t\t\t.select(`#${this.elId}`)\n\t\t\t\t\t.fields({\n\t\t\t\t\t\tsize: true\n\t\t\t\t\t}, data => {\n\t\t\t\t\t\tif (index >= 10) return\n\t\t\t\t\t\tif (!data) {\n\t\t\t\t\t\t\tindex++\n\t\t\t\t\t\t\tthis.getCollapseHeight(index)\n\t\t\t\t\t\t\treturn\n\t\t\t\t\t\t}\n\t\t\t\t\t\t// #ifdef APP-NVUE\n\t\t\t\t\t\tthis.height = data.height + 1\n\t\t\t\t\t\t// #endif\n\t\t\t\t\t\t// #ifndef APP-NVUE\n\t\t\t\t\t\tthis.height = data.height\n\t\t\t\t\t\t// #endif\n\t\t\t\t\t\tthis.isHeight = true\n\t\t\t\t\t})\n\t\t\t\t\t.exec()\n\t\t\t},\n\t\t\tgetNvueHeight() {\n\t\t\t\tconst result = dom.getComponentRect(this.$refs['fui_collapse__el'], option => {\n\t\t\t\t\tif (option && option.result && option.size) {\n\t\t\t\t\t\t// #ifdef APP-NVUE\n\t\t\t\t\t\tthis.height = option.size.height + 1\n\t\t\t\t\t\t// #endif\n\t\t\t\t\t\t// #ifndef APP-NVUE\n\t\t\t\t\t\tthis.height = option.size.height\n\t\t\t\t\t\t// #endif\n\t\t\t\t\t\tthis.isHeight = true\n\t\t\t\t\t}\n\t\t\t\t})\n\t\t\t},\n\t\t\tgetCollapse(name = 'fui-collapse') {\n\t\t\t\tlet parent = this.$parent;\n\t\t\t\tlet parentName = parent.$options.name;\n\t\t\t\twhile (parentName !== name) {\n\t\t\t\t\tparent = parent.$parent;\n\t\t\t\t\tif (!parent) return false;\n\t\t\t\t\tparentName = parent.$options.name;\n\t\t\t\t}\n\t\t\t\treturn parent;\n\t\t\t}\n\t\t}\n\t}\n</script>\n\n<style scoped>\n\t.fui-collapse__item {\n\t\t/* #ifndef APP-NVUE */\n\t\tbox-sizing: border-box;\n\t\t/* #endif */\n\t}\n\n\t.fui-collapse-item__title {\n\t\t/* #ifndef APP-NVUE */\n\t\tdisplay: flex;\n\t\twidth: 100%;\n\t\tbox-sizing: border-box;\n\t\t/* #endif */\n\t\tflex-direction: row;\n\t\talign-items: center;\n\t\ttransition: border-bottom-color 0.3s;\n\n\t\t/* #ifdef H5 */\n\t\tcursor: pointer;\n\t\t/* #endif */\n\t\tposition: relative;\n\t}\n\n\t.fui-collapse__border {\n\t\tposition: absolute;\n\t\tbottom: 0;\n\t\tright: 0;\n\t\t/* #ifdef APP-NVUE */\n\t\theight: 0.5px;\n\t\tz-index: -1;\n\t\t/* #endif */\n\t\t/* #ifndef APP-NVUE */\n\t\theight: 1px;\n\t\t-webkit-transform: scaleY(0.5);\n\t\ttransform: scaleY(0.5);\n\t\ttransform-origin: 0 100%;\n\t\tz-index: 1;\n\t\t/* #endif */\n\t}\n\n\t/* #ifndef APP-NVUE */\n\t.fui-collapse__border-color {\n\t\tbackground: var(--fui-color-border, #EEEEEE) !important;\n\t}\n\n\t/* #endif */\n\n\t.fui-collapse__disabled {\n\t\topacity: .5;\n\t\t/* #ifdef H5 */\n\t\tcursor: not-allowed;\n\t\t/* #endif */\n\t}\n\n\t.fui-collapse__title {\n\t\tflex: 1;\n\t\toverflow: hidden;\n\t}\n\n\n\t.fui-collapse__arrow-inner {\n\t\theight: 40rpx;\n\t\twidth: 40rpx;\n\t\tborder-width: 0 3px 3px 0;\n\t\tborder-style: solid;\n\t\ttransform: rotate(45deg) scale(.5);\n\t\t/* #ifndef APP-NVUE */\n\t\tbox-sizing: border-box;\n\t\t/* #endif */\n\t\tposition: absolute;\n\t\ttop: -6rpx;\n\t\tleft: 0;\n\t}\n\n\t.fui-collapse__arrow {\n\t\twidth: 40rpx;\n\t\theight: 40rpx;\n\t\tposition: relative;\n\t\t/* #ifndef APP-NVUE */\n\t\tflex-shrink: 0;\n\t\t/* #endif */\n\t}\n\n\t.fui-collapse__arrow-close {\n\t\ttransform: rotate(0deg);\n\t}\n\n\t.fui-collapse__arrow-active {\n\t\ttransform: rotate(180deg);\n\t}\n\n\t.fui-collapse__item-ani {\n\t\ttransition-property: transform;\n\t\ttransition-duration: 0.3s;\n\t\ttransition-timing-function: ease;\n\t}\n\n\t.fui-collapse__content-wrap {\n\t\t/* #ifndef APP-NVUE */\n\t\twill-change: height;\n\t\tbox-sizing: border-box;\n\t\t/* #endif */\n\t\toverflow: hidden;\n\t\tposition: relative;\n\t\theight: 0;\n\t}\n\n\t.fui-collapse-__content-ani {\n\t\ttransition-property: height;\n\t\ttransition-duration: 0.3s;\n\t\t/* #ifndef APP-NVUE */\n\t\twill-change: height;\n\t\t/* #endif */\n\t}\n\n\t.fui-collapse__content {\n\t\t/* #ifndef APP-NVUE */\n\t\twidth: 100%;\n\t\t/* #endif */\n\t\tposition: absolute;\n\t}\n\n\t.fui-collapse__content-open {\n\t\tposition: relative;\n\t}\n</style>","import Component from 'F:/MyGithub/myself-acgi-mpweixin/src/components/firstui/fui-collapse-item/fui-collapse-item.vue'\nwx.createComponent(Component)"],"names":["uni"],"mappings":";;AA8BC,MAAK,YAAU;AAAA,EACd,MAAM;AAAA,EACN,OAAO,CAAC,QAAQ;AAAA,EAChB,OAAO;AAAA;AAAA,IAEN,OAAO;AAAA,MACN,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AAAA;AAAA,IAED,UAAU;AAAA,MACT,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA,IACD,YAAY;AAAA,MACX,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA;AAAA,IAED,WAAW;AAAA,MACV,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA;AAAA,IAED,MAAM;AAAA,MACL,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA,IACD,UAAU;AAAA,MACT,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA,IAQD,aAAa;AAAA,MACZ,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA,IAED,YAAY;AAAA,MACX,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AAAA,IACD,OAAO;AAAA,MACN,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA,IACD,YAAY;AAAA,MACX,MAAM;AAAA,MACN,SAAS;AAAA,IACT;AAAA,IACD,YAAY;AAAA,MACX,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AA